import{_ as a,o as e,c as r,a2 as d}from"./chunks/framework.BWuWLRhz.js";const u=JSON.parse('{"title":"示例：某设备采购合同审核报告","description":"对某企业设备采购合同的法律审查与风险分析，重点审查付款条款、交付验收、违约责任及争议解决机制","frontmatter":{"title":"示例：某设备采购合同审核报告","date":"2025-07-12T00:00:00.000Z","sort":1,"description":"对某企业设备采购合同的法律审查与风险分析，重点审查付款条款、交付验收、违约责任及争议解决机制","head":[["meta",{"property":"og:title","content":"示例：某设备采购合同审核报告"}],["meta",{"property":"og:description","content":"对某企业设备采购合同的法律审查与风险分析，重点审查付款条款、交付验收、违约责任及争议解决机制"}],["meta",{"property":"og:image","content":"https://corepop.cn/images/og-default.png"}],["meta",{"property":"og:url","content":"https://corepop.cn/works/2025-07-12-示例合同审核报告"}],["meta",{"property":"twitter:title","content":"示例：某设备采购合同审核报告"}],["meta",{"property":"twitter:description","content":"对某企业设备采购合同的法律审查与风险分析，重点审查付款条款、交付验收、违约责任及争议解决机制"}],["meta",{"property":"twitter:image","content":"https://corepop.cn/images/og-default.png"}]]},"headers":[],"relativePath":"works/2025-07-12-示例合同审核报告.md","filePath":"works/2025-07-12-示例合同审核报告.md","lastUpdated":null}'),o={name:"works/2025-07-12-示例合同审核报告.md"};function n(l,t,i,h,s,p){return e(),r("div",null,[...t[0]||(t[0]=[d('<h1 id="示例-某设备采购合同审核报告" tabindex="-1">示例：某设备采购合同审核报告 <a class="header-anchor" href="#示例-某设备采购合同审核报告" aria-label="Permalink to &quot;示例：某设备采购合同审核报告&quot;">​</a></h1><h2 id="一、审查概况" tabindex="-1">一、审查概况 <a class="header-anchor" href="#一、审查概况" aria-label="Permalink to &quot;一、审查概况&quot;">​</a></h2><table tabindex="0"><thead><tr><th>项目</th><th>内容</th></tr></thead><tbody><tr><td>合同类型</td><td>设备采购合同</td></tr><tr><td>合同金额</td><td>¥XXX,XXX.XX</td></tr><tr><td>风险等级</td><td>中等</td></tr><tr><td>审查日期</td><td>2025年7月12日</td></tr></tbody></table><h2 id="二、主要发现" tabindex="-1">二、主要发现 <a class="header-anchor" href="#二、主要发现" aria-label="Permalink to &quot;二、主要发现&quot;">​</a></h2><h3 id="一-付款条款风险" tabindex="-1">（一）付款条款风险 <a class="header-anchor" href="#一-付款条款风险" aria-label="Permalink to &quot;（一）付款条款风险&quot;">​</a></h3><p>第三条约定&quot;合同签订后7日内支付全部货款&quot;。该条款对买方极为不利：</p><ul><li><strong>风险</strong>：丧失付款杠杆，验收阶段完全被动</li><li><strong>建议</strong>：改为分阶段付款（签订付30% → 到货验收付60% → 质保期满付10%）</li></ul><h3 id="二-交付与验收条款" tabindex="-1">（二）交付与验收条款 <a class="header-anchor" href="#二-交付与验收条款" aria-label="Permalink to &quot;（二）交付与验收条款&quot;">​</a></h3><p>第六条验收标准过于笼统：</p><ul><li><strong>风险</strong>：&quot;符合行业标准&quot;缺乏可操作性，易发生争议</li><li><strong>建议</strong>：附技术规格清单作为合同附件，明确验收标准和流程</li></ul><h3 id="三-违约责任" tabindex="-1">（三）违约责任 <a class="header-anchor" href="#三-违约责任" aria-label="Permalink to &quot;（三）违约责任&quot;">​</a></h3><p>第十条第2款违约金约定偏低（日万分之0.5）：</p><ul><li><strong>风险</strong>：违约成本低，供应商履约动力不足</li><li><strong>建议</strong>：调整至日千分之0.5-1，且设置下限金额</li></ul><h2 id="三、修改建议汇总" tabindex="-1">三、修改建议汇总 <a class="header-anchor" href="#三、修改建议汇总" aria-label="Permalink to &quot;三、修改建议汇总&quot;">​</a></h2><table tabindex="0"><thead><tr><th>条款</th><th>问题</th><th>建议</th></tr></thead><tbody><tr><td>第三条</td><td>100%预付</td><td>分期付款</td></tr><tr><td>第六条</td><td>验收标准模糊</td><td>附件化技术规格</td></tr><tr><td>第十条第2款</td><td>违约金过低</td><td>提高违约金比例</td></tr><tr><td>第十二条</td><td>管辖约定不明</td><td>明确约定买方所在地法院</td></tr></tbody></table><h2 id="四、风险等级评估" tabindex="-1">四、风险等级评估 <a class="header-anchor" href="#四、风险等级评估" aria-label="Permalink to &quot;四、风险等级评估&quot;">​</a></h2><table tabindex="0"><thead><tr><th>类别</th><th>等级</th><th>说明</th></tr></thead><tbody><tr><td>法律风险</td><td>🟡 中</td><td>条款本身不违法，但对买方保护不足</td></tr><tr><td>商业风险</td><td>🟡 中</td><td>付款方式对买方资金安全影响较大</td></tr><tr><td>操作风险</td><td>🟢 低</td><td>修改后操作性良好</td></tr></tbody></table><hr><blockquote><p><strong>免责声明</strong>：本报告仅供学术交流与专业探讨，不构成正式法律意见。</p></blockquote>',19)])])}const b=a(o,[["render",n]]);export{u as __pageData,b as default};
